@strawberry.type
class Seller:
    id: int
    name: str


@strawberry.type
class Category:
    id: int
    name: str


@strawberry.type
class Review:
    id: int
    rating: int
    comment: Optional[str]


@strawberry.type
class Image:
    id: int
    url: str
    alt_text: Optional[str]


@strawberry.type
class Product:
    id: int
    name: str
    description: Optional[str]
    price: str
    seller: Seller
    category: Category
    reviews: List[Review]
    images: List[Image]


def to_seller(model: SellerModel) -> Seller:
    return Seller(id=model.id, name=model.name)


def to_category(model: CategoryModel) -> Category:
    return Category(id=model.id, name=model.name)


def to_review(model: ReviewModel) -> Review:
    return Review(id=model.id, rating=model.rating, comment=model.comment)


def to_image(model: ImageModel) -> Image:
    return Image(id=model.id, url=model.url, alt_text=model.alt_text)


def to_product(model: ProductModel) -> Product:
    return Product(
        id=model.id,
        name=model.name,
        description=model.description,
        price=str(model.price),
        seller=to_seller(model.seller),
        category=to_category(model.category),
        reviews=[to_review(review) for review in model.reviews],
        images=[to_image(image) for image in model.images],
    )


@strawberry.type
class Query:
    @strawberry.field
    def products(self, id: Optional[int] = None, seller_id: Optional[int] = None, category_id: Optional[int] = None) -> List[Product]:
        with Session(engine) as session:
            stmt = (
                select(ProductModel)
                .options(
                    selectinload(ProductModel.seller),
                    selectinload(ProductModel.category),
                    selectinload(ProductModel.reviews),
                    selectinload(ProductModel.images),
                )
            )

            if id is not None:
                stmt = stmt.where(ProductModel.id == id)
            if seller_id is not None:
                stmt = stmt.where(ProductModel.seller_id == seller_id)
            if category_id is not None:
                stmt = stmt.where(ProductModel.category_id == category_id)

            models = session.scalars(stmt).all()
            return [to_product(model) for model in models]

    @strawberry.field
    def product(self, id: int) -> Optional[Product]:
        with Session(engine) as session:
            stmt = (
                select(ProductModel)
                .where(ProductModel.id == id)
                .options(
                    selectinload(ProductModel.seller),
                    selectinload(ProductModel.category),
                    selectinload(ProductModel.reviews),
                    selectinload(ProductModel.images),
                )
            )
            model = session.scalar(stmt)
            return to_product(model) if model else None

    @strawberry.field
    def sellers(self) -> List[Seller]:
        with Session(engine) as session:
            models = session.scalars(select(SellerModel)).all()
            return [to_seller(model) for model in models]

    @strawberry.field
    def categories(self) -> List[Category]:
        with Session(engine) as session:
            models = session.scalars(select(CategoryModel)).all()
            return [to_category(model) for model in models]


schema = strawberry.Schema(query=Query)

